inline short conv_int(const int i, short) { return (short)i; }
inline int conv_int(const int i, int) { return i; }
inline float conv_int(const int i, float) { return (float)i; }
#ifdef ENABLE_DP
inline double conv_int(const int i, double) { return (double)i; }
#endif
#ifdef ENABLE_HP
inline half2 conv_int(const int i, half2) {
  half h = convert_half_rte(i);
  return (half2)(h, h);
}
#endif

inline short mad_t(const short a, const short b, const short c) {
  return (short)(a * b + c);
}
inline int mad_t(const int a, const int b, const int c) { return a * b + c; }
inline float mad_t(const float a, const float b, const float c) {
  return a * b + c;
}
#ifdef ENABLE_DP
inline double mad_t(const double a, const double b, const double c) {
  return a * b + c;
}
#endif
#ifdef ENABLE_HP
inline half2 mad_t(const half2 a, const half2 b, const half2 c) {
  return a * b + c;
}
#endif

inline bool equal_t(const short a, const short b) { return a == b; }
inline bool equal_t(const int a, const int b) { return a == b; }
inline bool equal_t(const float a, const float b) { return a == b; }
#ifdef ENABLE_DP
inline bool equal_t(const double a, const double b) { return a == b; }
#endif
#ifdef ENABLE_HP
inline bool equal_t(const half2 a, const half2 b) { return all(a == b); }
#endif

__kernel void benchmark_func(class_T seed, __global class_T* g_data) {
  const uint blockSize = (uint)blockdim;
  const uint lid = get_local_id(0);
  const uint gid = get_global_id(0);
  const uint group = get_group_id(0);

#ifdef BLOCK_STRIDED
  const uint stride = blockSize;
  uint idx = group * blockSize * (uint)ELEMENTS_PER_THREAD + lid;
#else
  const uint stride = get_global_size(0);
  uint idx = gid;
#endif

  const uint big_stride = get_global_size(0) * (uint)ELEMENTS_PER_THREAD;

  class_T tmps[ELEMENTS_PER_THREAD];

  for (uint k = 0; k < (uint)FUSION_DEGREE; k++) {
    for (uint j = 0; j < (uint)ELEMENTS_PER_THREAD; j++) {
      tmps[j] = g_data[idx + j * stride + k * big_stride];
      for (int i = 0; i < (int)COMPUTE_ITERATIONS; i++) {
        tmps[j] = mad_t(tmps[j], tmps[j], seed);
      }
    }

    class_T sum = conv_int(0, (class_T)0);
    for (uint j = 0; j < (uint)ELEMENTS_PER_THREAD; j += 2) {
      sum = mad_t(tmps[j], tmps[j + 1], sum);
    }

    if (equal_t(sum, conv_int(-1, (class_T)0))) {
      g_data[idx + k * big_stride] = sum;
    }
  }
}
